// Enhanced fetch wrapper
const originalFetch = global.fetch;

global.fetch = function(...args) {
  const startTime = Date.now();
  const [url, options] = args;
  
  return originalFetch(...args)
    .then(response => {
      const duration = Date.now() - startTime;
      DebugLogger.logNetworkRequest(url, options?.method || 'GET', options?.body, response, duration);
      return response;
    })
    .catch(error => {
      const duration = Date.now() - startTime;
      DebugLogger.logNetworkRequest(url, options?.method || 'GET', options?.body, { error: error.message }, duration);
      throw error;
    });
};

